INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('2160', 'Kontokorrent Gesellschafter', 'A', 'L', 'AR_paid:AP_paid', '216', false, true, 'kontokorrent', 'Book expenses here that are clearly NOT business-related and must be charged to the owner''s personal account. Use only when an expense is very obviously private and non-business (high threshold). Examples: cinema tickets, private vacation bookings, personal clothing purchases, private gym memberships, personal streaming subscriptions. Do NOT use for any expense that could reasonably be business-related.', (SELECT id FROM chart WHERE accno = '216'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('220', 'KURZFRISTIGE VERZINSLICHE VERBINDLICHKEITEN GEGENÜBER STAATLICHEN STELLEN', 'H', 'L', '', '220', false, true, '', '', (SELECT id FROM chart WHERE accno = '20'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('2200', 'Geschuldete MWST', 'A', 'L', 'AP_amount', '220', false, true, '', 'VAT payable – settlement account (Geschuldete MWST). This is the main VAT liability account under the flat-rate method (Saldopauschale). Used for recording the VAT amount owed to the Swiss Federal Tax Administration (ESTV) based on the flat-rate percentage applied to gross revenue.', (SELECT id FROM chart WHERE accno = '220'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('2201', 'Abrechnungskto. MwSt.', 'A', 'L', 'AP_amount', '220', false, true, '', 'VAT settlement / clearing account (Abrechnungskonto MwSt). Used for reconciling periodic VAT returns under the flat-rate method (Saldopauschale). This account nets the VAT collected on sales against the flat-rate VAT liability to determine the final amount owed or receivable.', (SELECT id FROM chart WHERE accno = '220'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('22040', 'Bezugsteuer 8.1%', 'A', 'L', 'AP_tax', '220', false, true, '', 'Reverse charge VAT (Bezugsteuer) at 8.1% – liability side. Use when self-assessing VAT on services purchased from abroad. The reverse charge applies when a foreign supplier does not charge Swiss VAT. Even under the flat-rate method, reverse charge VAT must be declared and paid separately at the full rate.', (SELECT id FROM chart WHERE accno = '220'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('22050', 'Befreite Leistungen, Exporte MWST 0% (Ziff. 220)', 'A', 'L', '', '220', false, true, '', 'VAT-exempt supplies and exports at 0% (MWST declaration line 220). Use this tax code for genuinely VAT-exempt sales and exports. Examples: exported goods, services to foreign recipients where exemption applies. Revenue is reported but no VAT is charged.', (SELECT id FROM chart WHERE accno = '220'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('22051', 'Leistungen im Ausland MWST 0% (Ziff. 221)', 'A', 'L', '', '220', false, true, '', 'Services performed abroad at 0% (MWST declaration line 221). Use this tax code for services where the place of supply is outside Switzerland. No Swiss VAT applies. Examples: consulting for foreign clients where place of supply rules shift VAT abroad.', (SELECT id FROM chart WHERE accno = '220'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('22052', 'Nicht steuerbare Leistungen MWST 0% (Ziff. 230)', 'A', 'L', '', '220', false, true, '', 'Non-taxable services at 0% (MWST declaration line 230). Use this tax code for services explicitly excluded from Swiss VAT. Examples: certain financial services, insurance services, healthcare, education, and cultural services exempt under MWSTG.', (SELECT id FROM chart WHERE accno = '220'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('22053', 'Subventionen MWST 0% (Ziff. 900)', 'A', 'L', '', '220', false, true, '', 'Subsidies at 0% (MWST declaration line 900). Use this tax code when recording received subsidies and public contributions that are not subject to VAT but must be reported in the VAT return.', (SELECT id FROM chart WHERE accno = '220'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('22054', 'Spenden, Dividenden, Schadenersatz MWST 0% (Ziff. 910)', 'A', 'L', '', '220', false, true, '', 'Donations, dividends, and compensation payments at 0% (MWST declaration line 910). Use this tax code for received donations, dividend income, and damage compensation payments that are not subject to VAT but must be reported in the VAT return.', (SELECT id FROM chart WHERE accno = '220'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('22055', 'Nichtentgelt MWST 0%', 'A', 'L', '', '220', false, true, '', 'Non-consideration amounts at 0% (Nichtentgelt). Use this tax code for transactions without consideration that are not subject to VAT, such as certain internal transfers or non-commercial transactions.', (SELECT id FROM chart WHERE accno = '220'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('22060', 'Verrechnungssteuer', 'A', 'L', 'AP_amount', '220', false, true, '', 'Withholding tax (Verrechnungssteuer) liability at 35%. Use when recording the obligation to remit 35% withholding tax on dividends, interest, or other distributions paid by the company to shareholders or investors.', (SELECT id FROM chart WHERE accno = '220'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('221', 'ÜBRIGE KURZFRISTIGE VERBINDLICHKEITEN GEGENÜBER DRITTEN (UNVERZINSLICH)', 'H', 'L', '', '221', false, true, '', '', (SELECT id FROM chart WHERE accno = '20'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('2215', 'Kreditkarte', 'A', 'L', '', '221', false, true, 'kreditkarten', 'Book credit card company statements and settlement invoices here. Examples: monthly Visa/Mastercard/Amex settlement statements, credit card processing fee statements. This is the clearing account for credit card liabilities.', (SELECT id FROM chart WHERE accno = '221'));
