INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('2271', 'Kontokorrent AHV, IV, EO, ALV', 'A', 'L', 'AP_amount', '227', false, true, '', 'Book invoices from AHV/IV/EO/ALV compensation office here. Only for social insurance invoices and premium statements. Examples: quarterly AHV contribution statement, social security premium invoice from Ausgleichskasse.', (SELECT id FROM chart WHERE accno = '227'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('2272', 'Kontokorrent FAK', 'A', 'L', 'AP_amount', '227', false, true, '', 'Book invoices from family allowance fund (FAK/FamZG) here. Only for family allowance fund invoices and premium statements. Examples: quarterly FAK contribution invoice.', (SELECT id FROM chart WHERE accno = '227'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('2273', 'Kontokorrent Unfallversicherung', 'A', 'L', 'AP_amount', '227', false, true, '', 'Book invoices from accident insurance provider (UVG/Suva) here. Only for accident insurance invoices and premium statements. Examples: annual Suva premium invoice, UVG premium statement.', (SELECT id FROM chart WHERE accno = '227'));
INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('2274', 'Kontokorrent Krankentaggeldversicherung', 'A', 'L', 'AP_amount', '227', false, true, '', 'Book invoices from daily sickness benefit insurance provider (KTG) here. Only for sickness insurance invoices and premium statements. Examples: annual KTG premium invoice, daily sickness benefit premium statement.', (SELECT id FROM chart WHERE accno = '227'));
