INSERT INTO chart (accno, description, charttype, category, link, gifi_accno, contra, allow_gl, symbol_link, detail, parent_id) VALUES ('34970', 'MWST 8.1%', 'A', 'I', 'AR_tax:IC_taxpart:IC_taxservice', '340', false, true, '', 'Output VAT (MWST) at 8.1% – standard rate, flat-rate method (Saldopauschale). Use this tax code when booking sales invoices and revenue subject to the standard Swiss VAT rate of 8.1%. Under the flat-rate method, this rate is charged on invoices to customers, but the company remits only the agreed flat-rate percentage to ESTV.', (SELECT id FROM chart WHERE accno = '220'));
